/**
 * Seed the built-in dictionary_entries table with comprehensive HSK 1-6 vocabulary.
 *
 * Run:  npx tsx scripts/seed-dictionary.ts
 */
import Database from 'better-sqlite3';
import path from 'path';

const dbPath = path.join(process.cwd(), 'local.db');
const db = new Database(dbPath);
db.pragma('journal_mode = WAL');

// Create table if not exists
db.exec(`
  CREATE TABLE IF NOT EXISTS dictionary_entries (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    simplified TEXT NOT NULL,
    traditional TEXT,
    pinyin TEXT NOT NULL,
    meaning TEXT NOT NULL,
    hsk_level INTEGER,
    frequency INTEGER,
    part_of_speech TEXT
  );
  CREATE INDEX IF NOT EXISTS dict_simplified_idx ON dictionary_entries(simplified);
  CREATE INDEX IF NOT EXISTS dict_pinyin_idx ON dictionary_entries(pinyin);
  CREATE INDEX IF NOT EXISTS dict_hsk_idx ON dictionary_entries(hsk_level);
  CREATE INDEX IF NOT EXISTS dict_frequency_idx ON dictionary_entries(frequency);
`);

interface DictEntry {
  simplified: string;
  traditional?: string;
  pinyin: string;
  meaning: string;
  hskLevel?: number;
  frequency?: number;
  partOfSpeech?: string;
}

