// ─── Seed Logic ───

const existing = db.prepare('SELECT COUNT(*) as count FROM dictionary_entries').get() as { count: number };

if (existing.count > 0) {
  console.log(`⚠️  dictionary_entries already has ${existing.count} rows. Clearing and re-seeding...`);
  db.prepare('DELETE FROM dictionary_entries').run();
}

const insert = db.prepare(`
  INSERT INTO dictionary_entries (simplified, traditional, pinyin, meaning, hsk_level, frequency, part_of_speech)
  VALUES (?, ?, ?, ?, ?, ?, ?)
`);

const insertMany = db.transaction((rows: DictEntry[]) => {
  for (const r of rows) {
    insert.run(r.simplified, r.traditional ?? null, r.pinyin, r.meaning, r.hskLevel ?? null, r.frequency ?? null, r.partOfSpeech ?? null);
  }
});

console.log(`📚 Seeding ${entries.length} dictionary entries...`);
insertMany(entries);

const finalCount = db.prepare('SELECT COUNT(*) as count FROM dictionary_entries').get() as { count: number };
console.log(`✅ Done! ${finalCount.count} entries in dictionary_entries.`);

db.close();
